SELECT content_type, COUNT(*) AS content_count
FROM educational_content
GROUP BY content_type;

SELECT title, views
FROM educational_content
ORDER BY views DESC;

SELECT title, language, views
FROM educational_content
ORDER BY views DESC;

SELECT title, views, ratings
FROM educational_content
ORDER BY views DESC;

SELECT AVG(rating) AS average_rating, category
FROM product_catalog
GROUP BY category;

SELECT product_name
FROM product_catalog
WHERE inventory_count < 10;

SELECT user_id, COUNT(post_id) AS post_count
FROM forum_posts
GROUP BY user_id;
